<template><view class="page"><view class="card"><view class="title">你好，我是阿西</view><view class="subtitle">连接庆喜儿，开始家乡话陪伴体验</view><button class="btn" :loading="loading" @click="login">微信一键登录</button></view></view></template>
<script setup lang="ts">import{ref}from'vue';import{useAuthStore}from'@/stores/auth';const loading=ref(false);async function login(){loading.value=true;try{const code=await new Promise<string>((r,j)=>uni.login({provider:'weixin',success:x=>r(x.code),fail:j}));await useAuthStore().login(code);uni.reLaunch({url:'/pages/home/index'});}catch(e:any){uni.showToast({title:e.message||'登录失败',icon:'none'});}finally{loading.value=false;}}</script>
